easy.solution:
def sum_to(n):
    total = 0
    for i in range(1, n+1):
        total += i
    return total

medium.solution:
def find_primes(n):
    primes = []
    for num in range(2, n+1):
        is_prime = True
        for d in range(2, int(num**0.5)+1):
            if num % d == 0:
                is_prime = False
                break
        if is_prime: primes.append(num)
    return primes

hard.solution:
def flatten(arr):
    result = []
    for item in arr:
        if isinstance(item, list):
            result.extend(flatten(item))
        else:
            result.append(item)
    return result

